function HoverCard({ children, className, style, hoverBorder }) {
  const [hovered, setHovered] = useState(false)
  return (
    <div onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}
      className={className || s.hoverCard}
      style={{ borderColor: hovered ? (hoverBorder || T.blue) : undefined, transform: hovered ? 'translateY(-4px)' : undefined, boxShadow: hovered ? '0 12px 40px rgba(0,0,0,0.4)' : undefined, ...style }}>
      {children}
    </div>
  )
}

